import React, { useEffect, useRef } from 'react';

const InkCanvas: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d', { alpha: true });
    if (!ctx) return;

    let width = window.innerWidth;
    let height = window.innerHeight;
    let particles: Particle[] = [];
    let animationFrameId: number;

    // Ink particle class simulating mist/chi
    class Particle {
      x: number;
      y: number;
      vx: number;
      vy: number;
      size: number;
      alpha: number;
      fadeRate: number;
      type: 'mist' | 'ink';

      constructor() {
        this.x = Math.random() * width;
        this.y = Math.random() * height;
        this.type = Math.random() > 0.8 ? 'ink' : 'mist';

        if (this.type === 'mist') {
          this.size = Math.random() * 150 + 50;
          this.vx = (Math.random() - 0.5) * 0.2; // Slow horizontal drift
          this.vy = (Math.random() - 0.5) * 0.1;
          this.alpha = 0;
          this.fadeRate = Math.random() * 0.002 + 0.001;
        } else {
          // Ink drops/spots
          this.size = Math.random() * 5 + 2;
          this.vx = (Math.random() - 0.5) * 0.5;
          this.vy = Math.random() * 0.5 + 0.2; // Falling slightly
          this.alpha = 0;
          this.fadeRate = Math.random() * 0.005 + 0.002;
        }
      }

      update() {
        this.x += this.vx;
        this.y += this.vy;

        // Sine wave oscillation for more organic movement
        if (this.type === 'mist') {
            this.alpha += this.fadeRate;
            if (this.alpha > 0.15 || this.alpha < 0) {
                this.fadeRate = -this.fadeRate;
            }
        } else {
            // Ink fades in then out
            this.alpha += this.fadeRate;
            if (this.alpha > 0.6) {
                this.fadeRate = -this.fadeRate;
            }
        }
      }

      draw(ctx: CanvasRenderingContext2D) {
        ctx.save();
        ctx.beginPath();

        // Create soft gradients
        const gradient = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, this.size);

        if (this.type === 'mist') {
            gradient.addColorStop(0, `rgba(200, 210, 220, ${Math.max(0, this.alpha)})`);
            gradient.addColorStop(1, `rgba(200, 210, 220, 0)`);
        } else {
            gradient.addColorStop(0, `rgba(40, 44, 52, ${Math.max(0, this.alpha)})`);
            gradient.addColorStop(1, `rgba(40, 44, 52, 0)`);
        }

        ctx.fillStyle = gradient;
        ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        ctx.fill();
        ctx.restore();
      }

      isDead() {
        return (this.alpha <= 0 && this.fadeRate < 0);
      }
    }

    const resize = () => {
      width = window.innerWidth;
      height = window.innerHeight;
      const dpr = window.devicePixelRatio || 1;
      canvas.width = width * dpr;
      canvas.height = height * dpr;
      ctx.scale(dpr, dpr);
      canvas.style.width = `${width}px`;
      canvas.style.height = `${height}px`;
    };

    const initParticles = () => {
        // Initial population
        for(let i=0; i<30; i++) {
            particles.push(new Particle());
        }
    };

    const animate = () => {
      ctx.clearRect(0, 0, width, height);

      // Draw Mountains (Static Shapes at bottom) - simple bezier curves for "Shanshui" look
      ctx.save();
      ctx.fillStyle = "rgba(180, 190, 190, 0.2)";
      ctx.beginPath();
      ctx.moveTo(0, height);
      ctx.lineTo(0, height * 0.8);
      ctx.bezierCurveTo(width * 0.2, height * 0.7, width * 0.4, height * 0.9, width * 0.5, height * 0.85);
      ctx.bezierCurveTo(width * 0.7, height * 0.8, width * 0.9, height * 0.6, width, height * 0.8);
      ctx.lineTo(width, height);
      ctx.fill();

      ctx.fillStyle = "rgba(150, 160, 160, 0.3)";
      ctx.beginPath();
      ctx.moveTo(0, height);
      ctx.lineTo(0, height * 0.9);
      ctx.bezierCurveTo(width * 0.3, height * 0.95, width * 0.6, height * 0.85, width, height * 0.92);
      ctx.lineTo(width, height);
      ctx.fill();
      ctx.restore();


      // Maintain particle count
      if (particles.length < 50 && Math.random() < 0.05) {
        particles.push(new Particle());
      }

      for (let i = particles.length - 1; i >= 0; i--) {
        const p = particles[i];
        p.update();
        p.draw(ctx);
        if (p.isDead()) {
          particles.splice(i, 1);
        }
      }

      animationFrameId = requestAnimationFrame(animate);
    };

    window.addEventListener('resize', resize);
    resize();
    initParticles();
    animate();

    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      className="fixed inset-0 w-full h-full pointer-events-none z-0"
    />
  );
};

export default InkCanvas;

